import React, { useState, useCallback } from 'react';
import { Button, Select, dispatchAppToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../store/hooks';
import { MONTH_OPTIONS, yearOptions } from '../../constants/voucher';
import { ktService } from '../../services/kt/ktService';
import type { PeriodGateDto, PeriodJobEnqueueResultDto, PeriodProcessDocumentsDto } from '../../services/kt/models';
import { getApiErrorMessage } from '../../utils/getApiErrorMessage';
import { pollPeriodJobStatus } from '../../utils/pollPeriodJobStatus';
import { periodJobRunStatusLabel, periodProcessStatusLabel } from '../../utils/periodProcessStatusLabel';
import { PeriodProcessDocumentsSection } from './PeriodProcessDocumentsSection';
import df from '../../styles/documentForm.module.css';

export interface PeriodActionPanelProps {
  title: string;
  icon: string;
  description?: string;
  testIdPrefix?: string;
  showMonth?: boolean;
  gateMonth?: number;
  runLabel?: string;
  postLabel?: string;
  jobType?: string;
  jobStatusMonth?: (month: number) => number;
  /** JournalEntry.ReferenceNo — hiển thị bút toán chi tiết sau khi tính */
  referenceNo?: string;
  onRun: (month: number, year: number) => Promise<unknown>;
  onPost?: (month: number, year: number) => Promise<unknown>;
  getStatus?: (month: number, year: number) => Promise<string | null>;
  /** Nội dung bổ sung (preview, checklist…) — hiển thị sau kỳ, trước documents */
  renderExtra?: (ctx: { month: number; year: number }) => React.ReactNode;
  /** Khóa nút thực hiện bổ sung (vd. checklist đóng sổ chưa đủ) */
  runDisabledExtra?: boolean;
  /** Auth — ẩn nút khi false (`erp-form-toolbar-permissions.md`) */
  runPermitted?: boolean;
  postPermitted?: boolean;
}

const ASYNC_STATUSES = new Set(['Queued', 'Processing']);

export const PeriodActionPanel: React.FC<PeriodActionPanelProps> = ({
  title,
  icon,
  description,
  testIdPrefix = 'kt-period-action',
  showMonth = true,
  gateMonth,
  runLabel = 'Thực hiện',
  postLabel = 'Ghi sổ',
  jobType,
  jobStatusMonth = m => m,
  referenceNo,
  onRun,
  onPost,
  getStatus,
  renderExtra,
  runDisabledExtra = false,
  runPermitted = true,
  postPermitted = true,
}) => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(String(now.getMonth() + 1));
  const [year, setYear] = useState(String(now.getFullYear()));
  const [running, setRunning] = useState(false);
  const [posting, setPosting] = useState(false);
  const [statusLabel, setStatusLabel] = useState<string | null>(null);
  const [jobStatusLabel, setJobStatusLabel] = useState<string | null>(null);
  const [statusLoading, setStatusLoading] = useState(false);
  const [gate, setGate] = useState<PeriodGateDto | null>(null);
  const [gateLoading, setGateLoading] = useState(false);
  const [documents, setDocuments] = useState<PeriodProcessDocumentsDto | null>(null);
  const [documentsLoading, setDocumentsLoading] = useState(false);

  const m = Number(month);
  const y = Number(year);
  const periodKey = showMonth ? `${month}-${year}` : year;
  const gateM = gateMonth ?? m;
  const statusM = jobStatusMonth(m);

  const refreshDocuments = useCallback(() => {
    if (!referenceNo || !showMonth) {
      setDocuments(null);
      return;
    }
    setDocumentsLoading(true);
    ktService.getPeriodProcessDocuments(referenceNo, m, y)
      .then(setDocuments)
      .catch(() => setDocuments(null))
      .finally(() => setDocumentsLoading(false));
  }, [referenceNo, showMonth, m, y]);

  const refreshJobStatus = useCallback(() => {
    if (!jobType) {
      setJobStatusLabel(null);
      return;
    }
    ktService.getPeriodJobStatus(jobType, statusM, y)
      .then(s => setJobStatusLabel(periodJobRunStatusLabel(s.jobStatus)))
      .catch(() => setJobStatusLabel(null));
  }, [jobType, statusM, y]);

  const refreshStatus = useCallback(() => {
    if (!getStatus) return;
    setStatusLoading(true);
    getStatus(m, y)
      .then(setStatusLabel)
      .catch(() => setStatusLabel(null))
      .finally(() => setStatusLoading(false));
  }, [getStatus, m, y]);

  const loadGate = useCallback(() => {
    setGateLoading(true);
    ktService.getPeriodGate(gateM, y)
      .then(setGate)
      .catch(() => setGate(null))
      .finally(() => setGateLoading(false));
  }, [gateM, y]);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      if (cancelled) return;
      loadGate();
      refreshJobStatus();
      refreshDocuments();
      if (getStatus) {
        setStatusLoading(true);
        getStatus(m, y)
          .then(label => { if (!cancelled) setStatusLabel(label); })
          .catch(() => { if (!cancelled) setStatusLabel(null); })
          .finally(() => { if (!cancelled) setStatusLoading(false); });
      }
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [getStatus, loadGate, refreshDocuments, refreshJobStatus, periodKey, m, y]);

  const pollIfAsync = async (isPost: boolean) => {
    if (!jobType) return;
    const final = await pollPeriodJobStatus(
      () => ktService.getPeriodJobStatus(jobType, statusM, y),
    );
    setJobStatusLabel(periodJobRunStatusLabel(final.jobStatus));
    const expected = isPost ? 'Posted' : 'Calculated';
    if (final.jobStatus === 'Failed') {
      throw new Error(final.lastError ?? `${runLabel} thất bại`);
    }
    if (final.jobStatus !== expected && final.jobStatus !== 'Posted') {
      throw new Error(`Trạng thái không mong đợi: ${periodJobRunStatusLabel(final.jobStatus)}`);
    }
  };

  const handleActionResult = async (result: unknown, isPost: boolean) => {
    const enqueue = result as PeriodJobEnqueueResultDto | undefined;
    if (jobType && enqueue?.jobStatus && ASYNC_STATUSES.has(enqueue.jobStatus)) {
      setJobStatusLabel(periodJobRunStatusLabel(enqueue.jobStatus));
      await pollIfAsync(isPost);
    }
    refreshStatus();
    refreshJobStatus();
    refreshDocuments();
  };

  const canRun = (gate?.canRun ?? true) && !runDisabledExtra;
  const actionsDisabled = !canRun || gateLoading;

  const handleRun = async () => {
    if (actionsDisabled) return;
    setRunning(true);
    try {
      const result = await onRun(m, y);
      await handleActionResult(result, false);
      dispatchAppToast(dispatch, { message: `${runLabel} thành công`, type: 'success' });
    } catch (e: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(e, `${runLabel} thất bại`),
        type: 'error',
      });
    } finally {
      setRunning(false);
    }
  };

  const handlePost = async () => {
    if (!onPost || actionsDisabled) return;
    setPosting(true);
    try {
      const result = await onPost(m, y);
      await handleActionResult(result, true);
      dispatchAppToast(dispatch, { message: `${postLabel} thành công`, type: 'success' });
    } catch (e: unknown) {
      dispatchAppToast(dispatch, { message: getApiErrorMessage(e, `${postLabel} thất bại`), type: 'error' });
    } finally {
      setPosting(false);
    }
  };

  const tid = (suffix: string) => `${testIdPrefix}-${suffix}`;
  const yearOpts = yearOptions();

  return (
    <div className={df.page} data-testid={tid('page')}>
      <div className={df.stickyTop}>
        <div className={df.pageHeader}>
          <div className={df.titleGroup}>
            <div>
              <div className={df.titleRow}>
                <h1 className={df.title} data-testid={tid('title')}>
                  <i className={`fas ${icon}`} style={{ marginRight: 8 }} />
                  {title}
                </h1>
              </div>
              {description && (
                <p style={{ margin: '4px 0 0', fontSize: 13, color: 'var(--color-text-secondary, #6c757d)' }}>
                  {description}
                </p>
              )}
            </div>
          </div>
        </div>
      </div>

      <div className={df.section} data-testid={tid('section-period')}>
        <h2 className={df.sectionTitle}>Kỳ thực hiện</h2>
        {(gate?.message || gateLoading) && (
          <p
            data-testid={tid('gate')}
            style={{
              margin: '0 0 8px',
              fontSize: 13,
              color: canRun ? 'var(--color-text-secondary, #6c757d)' : 'var(--color-danger, #dc3545)',
            }}
          >
            {gateLoading ? 'Đang kiểm tra kỳ…' : gate?.message}
          </p>
        )}
        {getStatus && (
          <p
            data-testid={tid('status')}
            style={{ margin: '0 0 4px', fontSize: 13, color: 'var(--color-text-secondary, #6c757d)' }}
          >
            {statusLoading ? 'Đang tải trạng thái…' : (statusLabel ?? '—')}
          </p>
        )}
        {jobType && jobStatusLabel && (
          <p
            data-testid={tid('job-status')}
            style={{ margin: '0 0 12px', fontSize: 13, color: 'var(--color-text-secondary, #6c757d)' }}
          >
            Job: {jobStatusLabel}
          </p>
        )}
        <div className={df.row4}>
          {showMonth && (
            <div className={df.field} data-testid={tid('field-month')}>
              <label className={df.label}>Tháng</label>
              <Select value={month} onChange={e => setMonth(e.target.value)} options={MONTH_OPTIONS} />
            </div>
          )}
          <div className={df.field} data-testid={tid('field-year')}>
            <label className={df.label}>Năm</label>
            <Select value={year} onChange={e => setYear(e.target.value)} options={yearOpts} />
          </div>
          <div className={df.field} aria-hidden />
          <div className={df.field} aria-hidden />
        </div>
        <div className={df.footer} style={{ marginTop: 12, padding: 0, border: 'none', background: 'transparent' }}>
          {runPermitted && (
            <Button
              variant="primary"
              data-testid={tid('run-btn')}
              onClick={handleRun}
              loading={running}
              disabled={actionsDisabled}
            >
              {runLabel}
            </Button>
          )}
          {onPost && postPermitted && (
            <Button
              variant="secondary"
              data-testid={tid('post-btn')}
              onClick={handlePost}
              loading={posting}
              disabled={actionsDisabled}
            >
              {postLabel}
            </Button>
          )}
        </div>
      </div>

      {renderExtra?.({ month: m, year: y })}

      {referenceNo && (
        <PeriodProcessDocumentsSection
          documents={documents}
          loading={documentsLoading}
          testIdPrefix={tid('docs')}
        />
      )}
    </div>
  );
};
